# Utility classes and functions for geometric calculations

class Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

def distance_to_origin(p: Point) -> float:
    return (p.x ** 2 + p.y ** 2) ** 0.5

